// Generated by generate.ts — hidden adversarial suite for signal.
// Run via `npx tsx __audit__/signal.hidden.ts` inside the scratch project.
import { signal, computed, effect } from '../src/signal'

let failures = 0
async function check(name: string, got: unknown, want: unknown) {
  got = await got  // resolve promises transparently
  const ok = JSON.stringify(got) === JSON.stringify(want)
  console.log(`  ${ok ? 'PASS' : 'FAIL'} — ${name}`)
  if (!ok) {
    console.log(`       got:  ${JSON.stringify(got)}`)
    console.log(`       want: ${JSON.stringify(want)}`)
    failures++
  }
}

;(async () => {
await check("signal get", signal(42).get(), 42)
await check("signal set", (() => { const s = signal(0); s.set(99); return s.get() })(), 99)
await check("signal update", (() => { const s = signal(5); s.update(x=>x*2); return s.get() })(), 10)
await check("effect runs immediately", (() => { let ran = false; effect(() => { ran = true }); return ran })(), true)
await check("effect reacts to signal", (() => { const s = signal(0); let last = 0; effect(() => { last = s.get() }); s.set(42); return last })(), 42)
await check("computed derives", (() => { const s = signal(5); const c = computed(() => s.get() * 2); return c.get() })(), 10)
console.log(failures === 0 ? 'ALL PASS' : `${failures} FAILURE(S)`)
process.exit(failures === 0 ? 0 : 1)
})()
